import { NextResponse } from "next/server";
import path from "path";
import { pathToFileURL } from "url";

type Params = { carId: string; checkId: string };

export async function generateCarReportPdf(req: Request, params: Params) {
  const { carId, checkId } = params;

  const flaskBase = process.env.NEXT_PUBLIC_API_BASE_URL;
  if (!flaskBase) return new NextResponse("Missing FLASK_API_BASE", { status: 500 });

  // ✅ รับ auth ได้ทั้ง header และ cookie
  const auth = req.headers.get("authorization") ?? "";
  const cookie = req.headers.get("cookie") ?? "";

  if (!auth && !cookie) {
    return NextResponse.json(
      { message: "Missing token (no Authorization header and no Cookie)" },
      { status: 401 }
    );
  }

  const reportUrl = `${flaskBase}/api/cars/${carId}/checks/${checkId}/report`;

  const reportRes = await fetch(reportUrl, {
    headers: {
      ...(auth ? { Authorization: auth } : {}),
      ...(cookie ? { Cookie: cookie } : {}),
    },
    cache: "no-store",
  });

  if (!reportRes.ok) {
    const text = await reportRes.text().catch(() => "");
    return new NextResponse(text || "Failed to load report from Flask", { status: reportRes.status });
  }

  const json = await reportRes.json();
  const report = json?.data ?? json;

  const React = (await import("react")).default;
  const { Document, Page, Text, View, StyleSheet, Image, Font, renderToBuffer } =
    await import("@react-pdf/renderer");

  // ✅ ฟอนต์ไทย (แนะนำ NotoSansThai)
  const fontPath = path.join(process.cwd(), "public", "fonts", "NotoSansThai-Regular.ttf");
  Font.register({ family: "TH", src: pathToFileURL(fontPath).href });

  const styles = StyleSheet.create({
    page: { padding: 24, fontSize: 10, fontFamily: "TH" },
    logo: { width: 140, height: 32, marginBottom: 10 },
    title: { fontSize: 14, marginBottom: 10, fontFamily: "TH" },
    row: { flexDirection: "row", marginBottom: 4 },
    label: { width: 120 },
  });

  const logoUrl = `${flaskBase}/static/images/logo2.png`;

  const PdfDoc = () =>
    React.createElement(
      Document,
      null,
      React.createElement(
        Page,
        { size: "A4", style: styles.page },
        React.createElement(Image, { src: logoUrl, style: styles.logo }),
        React.createElement(Text, { style: styles.title }, "รายงานการตรวจเช็ครถ"),
        React.createElement(
          View,
          null,
          React.createElement(
            View,
            { style: styles.row },
            React.createElement(Text, { style: styles.label }, "บจก.:"),
            React.createElement(Text, null, report?.car?.company_name ?? "-")
          ),
          React.createElement(
            View,
            { style: styles.row },
            React.createElement(Text, { style: styles.label }, "ทะเบียนรถ:"),
            React.createElement(Text, null, report?.car?.registration_number ?? "-")
          ),
          React.createElement(
            View,
            { style: styles.row },
            React.createElement(Text, { style: styles.label }, "ครั้งที่:"),
            React.createElement(Text, null, report?.summary?.round ?? "-")
          )
        )
      )
    );

  const pdfBuffer = await renderToBuffer(React.createElement(PdfDoc));
  const body = new Uint8Array(pdfBuffer);

  return new NextResponse(body, {
    status: 200,
    headers: {
      "Content-Type": "application/pdf",
      // ✅ ไฟล์แนบ
      "Content-Disposition": `attachment; filename="car-report-${checkId}.pdf"`,
      "Cache-Control": "no-store",
    },
  });
}
